@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mt-3">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-20260501-10001)"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null && !isLoading)
{
    <div class="alert alert-warning mt-3">
        No shipment found with tracking number "<strong>@searchedNumber</strong>".
    </div>
}

@if (shipment is not null)
{
    <div class="card mt-4">
        <div class="card-header">
            <h5 class="mb-0">Shipment @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></dd>

                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>

                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>

                        <dt>Estimated Delivery</dt>
                        <dd>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</dd>

                        @if (shipment.ActualDelivery is not null)
                        {
                            <dt>Delivered On</dt>
                            <dd>@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>

            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @(GetProgressPercent(shipment.Status))%">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
        <div class="card-footer text-muted">
            Created: @shipment.CreatedAt.ToString("MMM dd, yyyy HH:mm") UTC
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool isLoading;
    private bool searched;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isLoading = true;
        searched = true;
        searchedNumber = trackingNumber.Trim();
        shipment = null;

        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}

