+        finally
+        {
+            isCreating = false;
+        }
+    }
+
+    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
+    {
+        if (e.Value is not string val || !int.TryParse(val, out var statusInt))
+            return;
