+@page "/shipments"
+@using ShipmentTracker.Client.Models
+@using ShipmentTracker.Client.Services
+@using Microsoft.AspNetCore.Authorization
+@attribute [Authorize]
+@inject IShipmentService ShipmentService
+
+<PageTitle>Shipments Dashboard</PageTitle>
+
+<h1>Shipments Dashboard</h1>
+
+<div class="row mb-3 align-items-end">
+    <div class="col-md-3">
+        <label class="form-label">Filter by Status</label>
+        <select class="form-select" @bind="selectedStatus" @bind:after="LoadShipments">
+            <option value="">All</option>
+            @foreach (var status in Enum.GetValues<ShipmentStatus>())
+            {
+                <option value="@status">@status</option>
+            }
+        </select>
+    </div>
+    <div class="col-md-3">
+        <button class="btn btn-success" @onclick="ShowCreateForm">
+            + New Shipment
+        </button>
+    </div>
+</div>
+
+@if (showCreateForm)
+{
+    <div class="card mb-4">
+        <div class="card-header">
+            <h5 class="mb-0">Create New Shipment</h5>
+        </div>
+        <div class="card-body">
+            <div class="row g-3">
+                <div class="col-md-6">
+                    <label class="form-label">Origin</label>
+                    <input type="text" class="form-control" @bind="newShipment.Origin" placeholder="City, State" />
+                </div>
+                <div class="col-md-6">
+                    <label class="form-label">Destination</label>
+                    <input type="text" class="form-control" @bind="newShipment.Destination" placeholder="City, State" />
+                </div>
+                <div class="col-md-6">
+                    <label class="form-label">Recipient Name</label>
+                    <input type="text" class="form-control" @bind="newShipment.RecipientName" />
+                </div>
+                <div class="col-md-6">
+                    <label class="form-label">Estimated Delivery</label>
+                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
+                </div>
+                <div class="col-md-12">
+                    <label class="form-label">Description</label>
+                    <input type="text" class="form-control" @bind="newShipment.Description" placeholder="Package contents" />
+                </div>
+                <div class="col-12">
+                    <button class="btn btn-primary me-2" @onclick="CreateShipment" disabled="@isCreating">
+                        @if (isCreating)
+                        {
+                            <span class="spinner-border spinner-border-sm me-1"></span>
+                        }
+                        Create Shipment
+                    </button>
+                    <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
+                </div>
+            </div>
+        </div>
+    </div>
+}
+
+@if (isLoading)
+{
+    <p><em>Loading shipments...</em></p>
+}
+else if (shipments is not null)
+{
+    <div class="table-responsive">
+        <table class="table table-striped table-hover">
+            <thead>
+                <tr>
+                    <th>Tracking #</th>
+                    <th>Origin</th>
+                    <th>Destination</th>
+                    <th>Recipient</th>
+                    <th>Status</th>
+                    <th>Est. Delivery</th>
+                    <th>Actions</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var s in shipments)
+                {
+                    <tr>
+                        <td><code>@s.TrackingNumber</code></td>
+                        <td>@s.Origin</td>
+                        <td>@s.Destination</td>
+                        <td>@s.RecipientName</td>
+                        <td><span class="badge @GetBadgeClass(s.Status)">@s.Status</span></td>
+                        <td>@(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
+                        <td>
+                            @if (s.Status is not ShipmentStatus.Delivered and not ShipmentStatus.Cancelled)
+                            {
+                                <select class="form-select form-select-sm d-inline-block" style="width: auto;"
+                                        value="@((int)s.Status)"
+                                        @onchange="e => UpdateStatus(s, e)">
+                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
+                                    {
+                                        <option value="@((int)status)">@status</option>
+                                    }
+                                </select>
+                            }
+                            else
+                            {
+                                <span class="text-muted">—</span>
+                            }
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+
+    @if (shipments.Count == 0)
+    {
+        <p class="text-muted">No shipments found.</p>
+    }
+}
